const int INFINITE_TIME = -1;
const int INF = INFINITE_TIME;
const int N_REACTANTS = 16;
broadcast chan reached[N_REACTANTS];
broadcast chan reaching, do_update;


typedef struct {
	int[-99980001, 99980001] b;
	int e;
} double_t;

const double_t zero = {0, 0};
const double_t INFINITE_TIME_DOUBLE = {-1000, -3}; //INFINITE_TIME (-1) translated into double
//R0 = ERK
int R0 := 0;
